SELECT name, year_of_birth
FROM laureates
WHERE laureate_id = 1;

SELECT COUNT(DISTINCT a.category) AS total_distinct_categories
FROM awards a
INNER JOIN laureate_universities lu ON a.laureate_id = lu.laureate_id;

SELECT MAX(university_count) AS max_university_count
FROM (
  SELECT COUNT(lu.university_id) AS university_count
  FROM laureate_universities lu
  GROUP BY lu.laureate_id
) t;
